# V0065
# Audit reference: Standalone downloader-executor with embedded complete V0064 fresh-JPL Venus publication source.
from __future__ import annotations

import base64
import gzip
import hashlib
import runpy
from pathlib import Path

VERSION = "V0065"
TARGET = Path("/content/VENUS_1769_V0027_FORMAT_STANDALONE_V0064.py")
EXPECTED_SHA256 = "aef13208b26c90e18064ee2508e1111b7da0e1d8ec5b0b02cf2dde5310227e9d"
PAYLOAD = (
    ""
    ""
)


def main() -> None:
    source = gzip.decompress(base64.b64decode(PAYLOAD))
    actual_sha256 = hashlib.sha256(source).hexdigest()
    if actual_sha256 != EXPECTED_SHA256:
        raise RuntimeError(
            f"Embedded V0064 SHA-256 mismatch: expected {EXPECTED_SHA256}, received {actual_sha256}."
        )
    text = source.decode("utf-8")
    if not text.startswith("# V0064\n"):
        raise RuntimeError("Embedded V0064 opening-version audit failed.")
    if not text.rstrip().endswith("# V0064"):
        raise RuntimeError("Embedded V0064 closing-version audit failed.")
    compile(text, str(TARGET), "exec")
    TARGET.write_text(text, encoding="utf-8")
    _namespace = runpy.run_path(str(TARGET), run_name="__main__")
    del _namespace


if __name__ == "__main__":
    main()
